NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
int n,x;
vector<int>ve;
void sort(vector<int> a,int t){
	if(t==0){
		for(int i=0;i<a.size();++i)
        {
            write(a[0]);
            pc(' ');
        }
		return;
	}vector<int> k[10];
	for(int i=0;i<a.size();++i)k[a[i]/t%10].push_back(a[i]);
	for(int i=0;i<10;++i)if(k[i].size())sort(k[i],t/10);
}
signed main(void){
